package com.example.debug.grpc;

import com.google.protobuf.Any;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import io.grpc.*;
import io.grpc.protobuf.StatusProto;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.util.LinkedHashMap;
import java.util.Map;

public class GlobalExceptionInterceptor implements ServerInterceptor {

    private static final String SERVICE_NAME = "DebugService";

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(Status status, Metadata trailers) {
                if (status.isOk()) {
                    super.close(status, trailers);
                    return;
                }

                // If the error already has detailed information, pass through
                Throwable cause = status.getCause();
                if (cause != null && !(cause instanceof StatusRuntimeException)) {
                    // Wrap with full details
                    StatusRuntimeException detailed = buildGlobalError(
                            call.getMethodDescriptor().getFullMethodName(),
                            status,
                            cause
                    );
                    com.google.rpc.Status rpcStatus = StatusProto.fromStatusAndTrailers(
                            detailed.getStatus(), detailed.getTrailers()
                    );
                    if (rpcStatus != null) {
                        StatusRuntimeException sre = StatusProto.toStatusRuntimeException(rpcStatus);
                        super.close(
                                Status.fromThrowable(sre),
                                sre.getTrailers() != null ? sre.getTrailers() : trailers
                        );
                        return;
                    }
                }

                super.close(status, trailers);
            }
        };

        try {
            return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(
                    next.startCall(wrappedCall, headers)) {

                @Override
                public void onHalfClose() {
                    try {
                        super.onHalfClose();
                    } catch (Exception e) {
                        StatusRuntimeException detailed = buildGlobalError(
                                call.getMethodDescriptor().getFullMethodName(),
                                Status.INTERNAL,
                                e
                        );
                        call.close(
                                Status.fromThrowable(detailed),
                                detailed.getTrailers() != null ? detailed.getTrailers() : new Metadata()
                        );
                    }
                }

                @Override
                public void onMessage(ReqT message) {
                    try {
                        super.onMessage(message);
                    } catch (Exception e) {
                        StatusRuntimeException detailed = buildGlobalError(
                                call.getMethodDescriptor().getFullMethodName(),
                                Status.INTERNAL,
                                e
                        );
                        call.close(
                                Status.fromThrowable(detailed),
                                detailed.getTrailers() != null ? detailed.getTrailers() : new Metadata()
                        );
                    }
                }
            };
        } catch (Exception e) {
            StatusRuntimeException detailed = buildGlobalError(
                    call.getMethodDescriptor().getFullMethodName(),
                    Status.INTERNAL,
                    e
            );
            call.close(
                    Status.fromThrowable(detailed),
                    detailed.getTrailers() != null ? detailed.getTrailers() : new Metadata()
            );
            return new ServerCall.Listener<ReqT>() {};
        }
    }

    private StatusRuntimeException buildGlobalError(String fullMethodName, Status status, Throwable exception) {
        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        exception.printStackTrace(pw);
        String stackTrace = sw.toString();

        Map<String, String> metadata = new LinkedHashMap<>();
        metadata.put("service", SERVICE_NAME);
        metadata.put("fullMethodName", fullMethodName);
        metadata.put("exceptionType", exception.getClass().getName());
        metadata.put("exceptionMessage", exception.getMessage() != null ? exception.getMessage() : "null");
        metadata.put("timestamp", String.valueOf(System.currentTimeMillis()));
        metadata.put("interceptorCaught", "true");
        metadata.put("originalStatusCode", status.getCode().name());

        DebugInfo debugInfo = DebugInfo.newBuilder()
                .setDetail("Unhandled exception in " + fullMethodName + ": " + exception.getClass().getName()
                        + " - " + exception.getMessage() + "\n\nFull Stack Trace:\n" + stackTrace)
                .build();

        ErrorInfo errorInfo = ErrorInfo.newBuilder()
                .setReason("UNHANDLED_EXCEPTION")
                .setDomain(SERVICE_NAME + ".interceptor")
                .putAllMetadata(metadata)
                .build();

        String message = String.format(
                "[INTERCEPTOR] Unhandled exception in %s: %s: %s\nStack: %s",
                fullMethodName,
                exception.getClass().getName(),
                exception.getMessage(),
                stackTrace
        );

        com.google.rpc.Status rpcStatus = com.google.rpc.Status.newBuilder()
                .setCode(status.getCode().value())
                .setMessage(message)
                .addDetails(Any.pack(debugInfo))
                .addDetails(Any.pack(errorInfo))
                .build();

        return StatusProto.toStatusRuntimeException(rpcStatus);
    }
}

// --- DebugGrpcServer.java ---
package com.example.debug.grpc;

import io.grpc.Server;
import io.grpc.ServerBuilder;

import java.io.IOException;

public class DebugGrpcServer {

    private Server server;
    private final int port;

    public DebugGrpcServer(int port) {
        this.port = port;
    }

    public void start() throws IOException {
        server = ServerBuilder.forPort(port)
                .addService(new DebugServiceImpl())
                .intercept(new GlobalExceptionInterceptor())
                .build()
                .start();

        System.out.println("Debug gRPC Server started on port " + port);
        System.out.println("WARNING: This server exposes detailed error information including stack traces,");
        System.out.println("internal state, and database errors. Use only for debugging purposes.");

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down gRPC server...");
            DebugGrpcServer.this.stop();
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        DebugGrpcServer server = new DebugGrpcServer(9090);
        server.start();
        server.blockUntilShutdown();
    }
}

