import com.google.protobuf.Any;
import com.google.protobuf.InvalidProtocolBufferException;
import com.google.rpc.BadRequest;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.concurrent.TimeUnit;

public class DebugGrpcClient {

    private final ManagedChannel channel;
    private final DebugServiceGrpc.DebugServiceBlockingStub blockingStub;

    public DebugGrpcClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = DebugServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void testGetUser(String userId) {
        System.out.println("\n=== Testing getUserData with userId: " + userId + " ===");
        try {
            UserRequest request = UserRequest.newBuilder()
                    .setUserId(userId)
                    .build();
            UserResponse response = blockingStub.getUserData(request);
            System.out.println("Success: " + response.getName() + " - " + response.getEmail());
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    public void testProcessOrder(String orderId, int quantity) {
        System.out.println("\n=== Testing processOrder with orderId: " + orderId + ", quantity: " + quantity + " ===");
        try {
            OrderRequest request = OrderRequest.newBuilder()
                    .setOrderId(orderId)
                    .setQuantity(quantity)
                    .build();
            OrderResponse response = blockingStub.processOrder(request);
            System.out.println("Success: " + response.getStatus());
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    public void testQueryDatabase(String query) {
        System.out.println("\n=== Testing queryDatabase with query: " + query + " ===");
        try {
            DbQueryRequest request = DbQueryRequest.newBuilder()
                    .setQuery(query)
                    .build();
            DbQueryResponse response = blockingStub.queryDatabase(request);
            System.out.println("Success: " + response.getResult());
        } catch (StatusRuntimeException e) {
            printDetailedError(e);
        }
    }

    private void printDetailedError(StatusRuntimeException e) {
        System.out.println("--- ERROR RECEIVED ---");
        System.out.println("gRPC Status Code: " + e.getStatus().getCode());
        System.out.println("Status Description: " + e.getStatus().getDescription());

        // Extract detailed error information from status proto
        Status status = StatusProto.fromThrowable(e);
        if (status != null) {
            System.out.println("\n[Full Error Message]:");
            System.out.println(status.getMessage());

            System.out.println("\n[Error Details]:");
            for (Any detail : status.getDetailsList()) {
                try {
                    if (detail.is(DebugInfo.class)) {
                        DebugInfo debugInfo = detail.unpack(DebugInfo.class);
                        System.out.println("\n  [DebugInfo]:");
                        System.out.println("  Detail: " + debugInfo.getDetail());
                        if (!debugInfo.getStackEntriesList().isEmpty()) {
                            System.out.println("  Stack Entries:");
                            for (String entry : debugInfo.getStackEntriesList()) {
                                System.out.println("    " + entry);
                            }
                        }
                    } else if (detail.is(ErrorInfo.class)) {
                        ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                        System.out.println("\n  [ErrorInfo]:");
                        System.out.println("  Reason: " + errorInfo.getReason());
                        System.out.println("  Domain: " + errorInfo.getDomain());
                        System.out.println("  Metadata:");
                        errorInfo.getMetadataMap().forEach((k, v) ->
                                System.out.println("    " + k + " = " + v));
                    } else if (detail.is(BadRequest.class)) {
                        BadRequest badRequest = detail.unpack(BadRequest.class);
                        System.out.println("\n  [BadRequest]:");
                        for (BadRequest.FieldViolation fv : badRequest.getFieldViolationsList()) {
                            System.out.println("  Field: " + fv.getField() + " - " + fv.getDescription());
                        }
                    }
                } catch (InvalidProtocolBufferException ex) {
                    System.out.println("  Failed to unpack detail: " + ex.getMessage());
                }
            }
        }
        System.out.println("--- END ERROR ---");
    }

    public static void main(String[] args) throws InterruptedException {
        DebugGrpcClient client = new DebugGrpcClient("localhost", 9090);

        try {
            // Test with empty user ID (validation error)
            client.testGetUser("");

            // Test with valid user ID (database error since DB is not running)
            client.testGetUser("user123");

            // Test with invalid quantity (validation error)
            client.testProcessOrder("order-001", -1);

            // Test with quantity exceeding inventory
            client.testProcessOrder("order-002", 100);

            // Test with valid order (payment processing error)
            client.testProcessOrder("order-003", 3);

            // Test empty query (validation error)
            client.testQueryDatabase("");

            // Test query (database connection error)
            client.testQueryDatabase("SELECT * FROM products");

        } finally {
            client.shutdown();
        }
    }
}